// Toma las posiciones del microservicio y arma mensajes para WhatsApp
const data = $input.first().json;
if (!data.ok) throw new Error('Microservicio respondio error: ' + (data.error || 'desconocido'));

const items = data.posiciones || [];
const perMsg = 7;
const chunks = [];
for (let i = 0; i < items.length; i += perMsg) {
  chunks.push(items.slice(i, i + perMsg));
}

const medals = { '1': '🥇', '2': '🥈', '3': '🥉' };
const total = chunks.length;
const fecha = new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

return chunks.map((chunk, idx) => {
  const header = idx === 0
    ? `⚽ *POLLA NOWBIT — COPA MUNDO 2026*\n_Tabla de posiciones · ${fecha}_\n\n`
    : '';
  const body = chunk.map(r => {
    const m = medals[r.posicion] || `${r.posicion}.`;
    return `${m} *${r.nombre}* (${r.usuario}) — ${r.puntos} pts`;
  }).join('\n');
  const footer = `\n\n_Parte ${idx + 1}/${total}_`;
  return { json: { text: header + body + footer, parte: idx + 1, total } };
});
